import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { datasetsApi, auth } from '../services/api';

const S = {
  page: { background: 'var(--color-bg)', minHeight: 'calc(100vh - 64px)' },
  hero: {
    background: 'var(--color-dark)', padding: '56px 32px 48px',
    borderBottom: '1px solid var(--color-dark-border)',
  },
  heroInner: { maxWidth: 960, margin: '0 auto' },
  back: { color: 'var(--color-dark-muted)', fontSize: 'var(--text-sm)', textDecoration: 'none', display: 'inline-flex', alignItems: 'center', gap: 6, marginBottom: 20 },
  heroName: { fontSize: 'clamp(1.75rem,4vw,2.75rem)', fontWeight: 900, color: '#fff', letterSpacing: '-0.02em', marginBottom: 10 },
  heroMeta: { display: 'flex', gap: 10, flexWrap: 'wrap', alignItems: 'center' },
  body: { maxWidth: 960, margin: '0 auto', padding: '40px 32px 80px' },
  tabs: { display: 'flex', borderBottom: '2px solid var(--color-stone)', marginBottom: 40, gap: 0 },
  tab: {
    padding: '12px 20px', border: 'none', background: 'none', cursor: 'pointer',
    fontSize: 'var(--text-sm)', fontWeight: 'var(--weight-medium)',
    color: 'var(--color-text-muted)', borderBottom: '2px solid transparent',
    marginBottom: -2, transition: 'all 150ms', fontFamily: 'var(--font-sans)',
  },
  tabActive: { color: 'var(--color-text-primary)', borderBottomColor: 'var(--color-gold)' },
  statsGrid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(160px,1fr))', gap: 16, marginBottom: 32 },
  statCard: { background: 'var(--color-surface)', border: '1px solid var(--color-stone)', borderRadius: 'var(--radius-lg)', padding: '16px' },
  statLabel: { fontSize: 'var(--text-xs)', fontWeight: 'var(--weight-semibold)', letterSpacing: 'var(--tracking-wider)', textTransform: 'uppercase', color: 'var(--color-text-muted)', marginBottom: 6 },
  statVal: { fontSize: 'var(--text-xl)', fontWeight: 'var(--weight-bold)', color: 'var(--color-text-primary)' },
  table: { width: '100%', borderCollapse: 'collapse', fontSize: 'var(--text-sm)' },
  th: { textAlign: 'left', padding: '10px 14px', background: 'var(--color-surface)', fontWeight: 'var(--weight-semibold)', color: 'var(--color-text-secondary)', borderBottom: '1px solid var(--color-stone)' },
  td: { padding: '10px 14px', borderBottom: '1px solid var(--color-stone)', color: 'var(--color-text-primary)', verticalAlign: 'top' },
  tdMuted: { padding: '10px 14px', borderBottom: '1px solid var(--color-stone)', color: 'var(--color-text-muted)', verticalAlign: 'top' },
  defList: { display: 'grid', gridTemplateColumns: '200px 1fr', gap: '1px', background: 'var(--color-stone)', border: '1px solid var(--color-stone)', borderRadius: 'var(--radius-lg)', overflow: 'hidden' },
  defTerm: { background: 'var(--color-surface)', padding: '12px 16px', fontSize: 'var(--text-sm)', fontWeight: 'var(--weight-medium)', color: 'var(--color-text-secondary)' },
  defVal: { background: '#fff', padding: '12px 16px', fontSize: 'var(--text-sm)', color: 'var(--color-text-primary)', wordBreak: 'break-all', fontFamily: 'var(--font-mono)' },
  codeBlock: { background: 'var(--color-dark)', color: 'var(--color-dark-text)', borderRadius: 'var(--radius-lg)', padding: '24px', fontFamily: 'var(--font-mono)', fontSize: 'var(--text-sm)', lineHeight: 1.8, overflowX: 'auto' },
  endpointBar: { display: 'flex', alignItems: 'center', gap: 10, padding: '12px 16px', background: 'var(--color-surface)', border: '1px solid var(--color-stone)', borderRadius: 'var(--radius-md)', marginBottom: 20, fontFamily: 'var(--font-mono)', fontSize: 'var(--text-sm)', overflowX: 'auto' },
  dataTable: { width: '100%', borderCollapse: 'collapse', fontSize: 'var(--text-xs)', overflowX: 'auto', display: 'block', maxHeight: 400 },
  authPrompt: { textAlign: 'center', padding: '48px 20px', background: 'var(--color-surface)', border: '1px solid var(--color-stone)', borderRadius: 'var(--radius-xl)' },
};

const TABS = ['Overview', 'Schema', 'Data Preview', 'Provenance', 'API Access'];

function CopyBtn({ text }) {
  const [copied, setCopied] = useState(false);
  return (
    <button onClick={() => { navigator.clipboard.writeText(text); setCopied(true); setTimeout(() => setCopied(false), 1800); }}
      className="btn btn-outline btn-sm">{copied ? '✓ Copied' : 'Copy'}</button>
  );
}

function formatBytes(bytes) {
  if (!bytes) return '—';
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1048576) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / 1048576).toFixed(1)} MB`;
}

export default function DatasetDetail() {
  const { slug } = useParams();
  const navigate = useNavigate();
  const [dataset, setDataset] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('Overview');
  const [data, setData] = useState(null);
  const [dataLoading, setDataLoading] = useState(false);
  const [dataPage, setDataPage] = useState(1);
  const [saved, setSaved] = useState(false);

  useEffect(() => {
    setLoading(true);
    datasetsApi.get(slug)
      .then(r => setDataset(r.data))
      .catch(() => setError('Dataset not found.'))
      .finally(() => setLoading(false));
  }, [slug]);

  useEffect(() => {
    if (activeTab === 'Data Preview' && auth.isLoggedIn()) {
      setDataLoading(true);
      datasetsApi.getData(slug, dataPage)
        .then(r => setData(r))
        .catch(() => setData(null))
        .finally(() => setDataLoading(false));
    }
  }, [activeTab, slug, dataPage]);

  if (loading) return (
    <div style={S.page}>
      <div style={{ ...S.hero }}>
        <div style={S.heroInner}>
          <div style={{ width: 200, height: 16, borderRadius: 6, marginBottom: 20 }} className="skeleton" />
          <div style={{ width: '50%', height: 36, borderRadius: 8, marginBottom: 12 }} className="skeleton" />
          <div style={{ display: 'flex', gap: 8 }}>
            {[80, 100, 70].map((w, i) => <div key={i} style={{ width: w, height: 24, borderRadius: 99 }} className="skeleton" />)}
          </div>
        </div>
      </div>
    </div>
  );

  if (error) return (
    <div style={{ ...S.page, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <div style={{ textAlign: 'center' }}>
        <div style={{ fontSize: '3rem', marginBottom: 16 }}>🗄️</div>
        <h2 style={{ marginBottom: 8 }}>Dataset Not Found</h2>
        <Link to="/explore" className="btn btn-primary" style={{ marginTop: 16 }}>Back to Explorer</Link>
      </div>
    </div>
  );

  let schema = { fields: [] };
  let stats = {};
  try { schema = JSON.parse(dataset.schema_info || '{}'); } catch { }
  try { stats = JSON.parse(dataset.statistics || '{}'); } catch { }
  let tags = [];
  try { tags = JSON.parse(dataset.tags || '[]'); } catch { }

  const BASE_URL = `${window.location.origin}/api/v1`;

  return (
    <div style={S.page} className="page-enter">
      {/* Hero */}
      <div style={S.hero}>
        <div style={S.heroInner}>
          <Link to="/explore" style={S.back}>← Back to Explorer</Link>
          <h1 style={S.heroName}>{dataset.name}</h1>
          <div style={S.heroMeta}>
            <span className="badge badge-gold">{dataset.domain}</span>
            <span className="badge badge-default">{dataset.category}</span>
            <span className="badge" style={{ background: 'rgba(255,255,255,0.08)', color: 'rgba(250,250,248,0.6)' }}>
              ⭐ {dataset.quality_score?.toFixed(1)} quality
            </span>
            <span className="badge badge-default">v{dataset.version}</span>
            <span className="badge badge-default">🔄 {dataset.sync_frequency}</span>
          </div>
        </div>
      </div>

      {/* Body */}
      <div style={S.body}>
        {/* Tabs */}
        <div style={S.tabs}>
          {TABS.map(t => (
            <button key={t} style={{ ...S.tab, ...(activeTab === t ? S.tabActive : {}) }} onClick={() => setActiveTab(t)}>
              {t}
            </button>
          ))}
        </div>

        {/* Overview */}
        {activeTab === 'Overview' && (
          <div className="animate-fade-in">
            <p style={{ color: 'var(--color-text-secondary)', lineHeight: 1.75, marginBottom: 32, fontSize: 'var(--text-base)' }}>
              {dataset.description}
            </p>
            <div style={S.statsGrid}>
              {[
                ['Records', (dataset.record_count || 0).toLocaleString()],
                ['File Size', formatBytes(dataset.file_size_bytes)],
                ['Version', `v${dataset.version}`],
                ['Sync', dataset.sync_frequency],
                ['Connector', dataset.connector],
                ['Quality', `${dataset.quality_score?.toFixed(1)}/10`],
              ].map(([l, v]) => (
                <div key={l} style={S.statCard}>
                  <div style={S.statLabel}>{l}</div>
                  <div style={S.statVal}>{v}</div>
                </div>
              ))}
            </div>
            {tags.length > 0 && (
              <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', marginBottom: 32 }}>
                {tags.map(t => <span key={t} className="tag">{t}</span>)}
              </div>
            )}
          </div>
        )}

        {/* Schema */}
        {activeTab === 'Schema' && (
          <div className="animate-fade-in">
            {schema.fields?.length > 0 ? (
              <table style={S.table}>
                <thead>
                  <tr>
                    <th style={S.th}>Field</th>
                    <th style={S.th}>Type</th>
                    <th style={S.th}>Null %</th>
                    <th style={S.th}>Description</th>
                  </tr>
                </thead>
                <tbody>
                  {schema.fields.map((f, i) => (
                    <tr key={f.name} style={{ background: i % 2 === 0 ? '#fff' : 'var(--color-surface)' }}>
                      <td style={S.td}><code style={{ fontFamily: 'var(--font-mono)', fontSize: 'var(--text-xs)' }}>{f.name}</code></td>
                      <td style={S.td}><span className="badge badge-default">{f.type}</span></td>
                      <td style={S.td}>{f.null_pct !== undefined ? `${f.null_pct}%` : '—'}</td>
                      <td style={S.tdMuted}>{f.description}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <div style={{ color: 'var(--color-text-muted)', textAlign: 'center', padding: 40 }}>Schema will be populated after first sync.</div>
            )}
          </div>
        )}

        {/* Data Preview */}
        {activeTab === 'Data Preview' && (
          <div className="animate-fade-in">
            {!auth.isLoggedIn() ? (
              <div style={S.authPrompt}>
                <div style={{ fontSize: '2.5rem', marginBottom: 16 }}>🔐</div>
                <h3 style={{ marginBottom: 8 }}>Sign in to preview data</h3>
                <p style={{ color: 'var(--color-text-muted)', marginBottom: 20 }}>Create a free account to preview records and get your API key.</p>
                <Link to="/login" className="btn btn-primary">Sign In</Link>
              </div>
            ) : dataLoading ? (
              <div style={{ textAlign: 'center', padding: 40 }}><span className="spinner spinner-lg" /></div>
            ) : data?.data?.length > 0 ? (
              <>
                <div style={{ overflowX: 'auto', borderRadius: 'var(--radius-lg)', border: '1px solid var(--color-stone)' }}>
                  <table style={{ ...S.table, fontSize: 'var(--text-xs)', minWidth: 600 }}>
                    <thead>
                      <tr>{Object.keys(data.data[0]).map(k => <th key={k} style={S.th}>{k}</th>)}</tr>
                    </thead>
                    <tbody>
                      {data.data.map((row, i) => (
                        <tr key={i} style={{ background: i % 2 === 0 ? '#fff' : 'var(--color-surface)' }}>
                          {Object.values(row).map((v, j) => (
                            <td key={j} style={{ ...S.td, maxWidth: 200, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                              {v === null ? <span style={{ color: 'var(--color-text-muted)' }}>null</span> : String(v)}
                            </td>
                          ))}
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
                <div style={{ display: 'flex', gap: 8, marginTop: 16 }}>
                  <button className="btn btn-outline btn-sm" disabled={dataPage === 1} onClick={() => setDataPage(p => p - 1)}>‹ Prev</button>
                  <button className="btn btn-outline btn-sm" onClick={() => setDataPage(p => p + 1)}>Next ›</button>
                </div>
              </>
            ) : (
              <div style={{ textAlign: 'center', padding: 40, color: 'var(--color-text-muted)' }}>No preview data available yet.</div>
            )}
          </div>
        )}

        {/* Provenance */}
        {activeTab === 'Provenance' && (
          <div className="animate-fade-in" style={S.defList}>
            {[
              ['Source', dataset.source || '—'],
              ['Source URL', dataset.source_url || '—'],
              ['Connector', dataset.connector],
              ['License', dataset.license || '—'],
              ['Version', dataset.version],
              ['Processing Status', dataset.processing_status],
              ['Integrity Hash', dataset.integrity_hash || 'Not computed yet'],
              ['Last Sync', dataset.last_sync ? new Date(dataset.last_sync).toLocaleString() : 'Never'],
              ['Next Sync', dataset.next_sync ? new Date(dataset.next_sync).toLocaleString() : '—'],
            ].map(([k, v]) => (
              <React.Fragment key={k}>
                <div style={S.defTerm}>{k}</div>
                <div style={S.defVal}>{v}</div>
              </React.Fragment>
            ))}
          </div>
        )}

        {/* API Access */}
        {activeTab === 'API Access' && (
          <div className="animate-fade-in">
            <div style={{ marginBottom: 28 }}>
              <div style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--weight-medium)', color: 'var(--color-text-secondary)', marginBottom: 8 }}>Endpoint URL</div>
              <div style={S.endpointBar}>
                <span style={{ color: 'var(--color-emerald)', fontWeight: 'var(--weight-semibold)' }}>GET</span>
                <span style={{ flex: 1 }}>{BASE_URL}/datasets/{slug}/data</span>
                <CopyBtn text={`${BASE_URL}/datasets/${slug}/data`} />
              </div>
            </div>
            <div style={{ marginBottom: 28 }}>
              <div style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--weight-medium)', color: 'var(--color-text-secondary)', marginBottom: 8 }}>Authentication</div>
              <div style={S.endpointBar}>
                <code>Authorization: Bearer omni_YourAPIKeyHere</code>
                <CopyBtn text="Authorization: Bearer omni_YourAPIKeyHere" />
              </div>
            </div>
            <div style={{ marginBottom: 28 }}>
              <div style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--weight-medium)', color: 'var(--color-text-secondary)', marginBottom: 8 }}>Python Example</div>
              <div style={S.codeBlock}>{`import requests

API_KEY = "omni_YourAPIKeyHere"
BASE_URL = "${BASE_URL}"

response = requests.get(
    f"{BASE_URL}/datasets/${slug}/data",
    headers={"Authorization": f"Bearer {API_KEY}"},
    params={"page": 1, "page_size": 20}
)
data = response.json()
print(f"Retrieved {data['count']} records.")
for record in data["data"]:
    print(record)`}</div>
            </div>
            <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
              <Link to={`/console?endpoint=/api/v1/datasets/${slug}/data`} className="btn btn-primary">
                Open in API Console
              </Link>
              {auth.isLoggedIn() && (
                <button className={`btn ${saved ? 'btn-emerald' : 'btn-outline'}`}
                  onClick={() => { datasetsApi.save(slug).then(() => setSaved(true)).catch(() => {}); }}>
                  {saved ? '✓ Saved' : '+ Save Dataset'}
                </button>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
